export const pickRandomAudioModule = (chordId: EguchiChordId) => {
  const entries = AUDIO_PACK_FILES_BY_CHORD[chordId] ?? [];
  if (!entries.length) return null;
  const index = Math.floor(Math.random() * entries.length);
  return entries[index];
};
